import{c as t,Q as a,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"The Rundown AI — 2026-05-10","description":"","frontmatter":{"title":"The Rundown AI — 2026-05-10","date":"2026-05-10T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-10-the-rundown-ai.md","filePath":"research/ai-news/2026-05/2026-05-10-the-rundown-ai.md","lastUpdated":1779898012000}'),o={name:"research/ai-news/2026-05/2026-05-10-the-rundown-ai.md"};function i(s,e,m,l,p,u){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="🗞️-the-rundown-ai-—-2026-05-10" tabindex="-1">🗞️ The Rundown AI — 2026-05-10 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-05-10" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-05-10&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="openai-closes-reasoning-gap-in-voice-agents" tabindex="-1"><a href="https://www.therundown.ai/p/openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">OpenAI closes reasoning gap in voice agents</a> <a class="header-anchor" href="#openai-closes-reasoning-gap-in-voice-agents" aria-label="Permalink to &quot;[OpenAI closes reasoning gap in voice agents](https://www.therundown.ai/p/openai-closes-reasoning-gap-in-voice-agents)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-08</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://pages.awscloud.com/awsmp-gim-jqup-adhoc-aim-ent-ai-data-leader-book-1-ent.html?trk=1c32ad2e-b511-4f96-bbcb-e6ae04147f9d&amp;sc_channel=el&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> Typing made AI useful, but speech is where agents have to prove they can keep up with real life.</p><p>OpenAI&#39;s new real-time voice model trio is built for that messier interface, adding a major reasoning upgrade, the ability to talk while thinking, and capable tool use that moves AI voice agents closer to running tasks at the speed of natural conversation.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>OpenAI’s reasoning upgrade for voice agents</p></li><li><p>Google folds Fitbit into its AI health play</p></li><li><p>Test multiple AI models with same prompt</p></li><li><p>Anthropic plans for AI that builds itself</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="openai" tabindex="-1">OPENAI <a class="header-anchor" href="#openai" aria-label="Permalink to &quot;OPENAI&quot;">​</a></h6><h4 id="🗣️-openai-s-reasoning-upgrade-for-voice-agents" tabindex="-1">🗣️ <a href="https://openai.com/index/advancing-voice-intelligence-with-new-models-in-the-api/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer"><strong>OpenAI’s reasoning upgrade for voice agents</strong></a> <a class="header-anchor" href="#🗣️-openai-s-reasoning-upgrade-for-voice-agents" aria-label="Permalink to &quot;🗣️ [**OpenAI’s reasoning upgrade for voice agents**](https://openai.com/index/advancing-voice-intelligence-with-new-models-in-the-api/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)&quot;">​</a></h4><p>Image source: OpenAI</p><p><strong>The Rundown:</strong> OpenAI just <a href="https://openai.com/index/advancing-voice-intelligence-with-new-models-in-the-api/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">introduced</a> GPT-Realtime-2, GPT-Realtime-Translate, and GPT-Realtime-Whisper, three API voice models that bring new reasoning, streaming, tool use, realism, and more capability upgrades to AI voice agents and live speech.</p><p><strong>The details:</strong></p><ul><li><p>Realtime-2 brings GPT-5-level reasoning to live speech, is able to use multiple tools at once, talks while it thinks, and has better tone control for realism.</p></li><li><p>On Big Bench Audio, Realtime-2 hit 96.6% vs. 81.4% for its predecessor, a 15-point jump in how well voice AI can reason in real-time.</p></li><li><p>OpenAI also shipped a live translator covering 70+ languages and a streaming transcription model, rounding out a full voice-agent toolkit.</p></li><li><p>OAI said Zillow, Priceline, and Deutsche Telekom are already building on the models for real estate AI agents, voice-managed travel, and customer support.</p></li></ul><p><strong>Why it matters:</strong> AI voice’s turn-based era appears to be nearing a close, with OAI’s new model moving to systems that can reason better, leverage tools, and complete workflows without awkward interruptions that take users out of a natural flow. The AI industry is fixated on text agents, but the next wave will be spoken to, not typed at.</p><h6 id="together-with-aws-marketplace" tabindex="-1">TOGETHER WITH AWS MARKETPLACE <a class="header-anchor" href="#together-with-aws-marketplace" aria-label="Permalink to &quot;TOGETHER WITH AWS MARKETPLACE&quot;">​</a></h6><h4 id="📊-15-enterprise-leaders-on-getting-data-ai-ready" tabindex="-1">📊****<a href="https://pages.awscloud.com/awsmp-gim-jqup-adhoc-aim-ent-ai-data-leader-book-1-ent.html?trk=1c32ad2e-b511-4f96-bbcb-e6ae04147f9d&amp;sc_channel=el&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer"><strong>15+ enterprise leaders on getting data AI-ready</strong></a> <a class="header-anchor" href="#📊-15-enterprise-leaders-on-getting-data-ai-ready" aria-label="Permalink to &quot;📊****[**15+ enterprise leaders on getting data AI-ready**](https://pages.awscloud.com/awsmp-gim-jqup-adhoc-aim-ent-ai-data-leader-book-1-ent.html?trk=1c32ad2e-b511-4f96-bbcb-e6ae04147f9d&amp;sc_channel=el&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)&quot;">​</a></h4><p><a href="https://pages.awscloud.com/awsmp-gim-jqup-adhoc-aim-ent-ai-data-leader-book-1-ent.html?trk=1c32ad2e-b511-4f96-bbcb-e6ae04147f9d&amp;sc_channel=el&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown</strong> : AWS Marketplace just released a free book featuring 15 chapters from senior data and AI leaders at JPMorgan Chase, Siemens, Mercedes-Benz, Roche, and more — each sharing practical advice on building the data infrastructure needed for agentic analytics and intelligent agents.</p><p><strong>Chapters cover topics including:</strong></p><ul><li><p>Evolving data strategy for agentic AI and scaling data products</p></li><li><p>Building on existing infrastructure with a pragmatic, business-first approach</p></li><li><p>Unlocking value with classical ML, semantic layers, and cross-team alignment</p></li><li><p>Real-world perspectives from leaders across different industries</p></li></ul><p><a href="https://pages.awscloud.com/awsmp-gim-jqup-adhoc-aim-ent-ai-data-leader-book-1-ent.html?trk=1c32ad2e-b511-4f96-bbcb-e6ae04147f9d&amp;sc_channel=el&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Get your free digital copy today</a>.</p><h6 id="google" tabindex="-1">GOOGLE <a class="header-anchor" href="#google" aria-label="Permalink to &quot;GOOGLE&quot;">​</a></h6><h4 id="⌚️-google-folds-fitbit-into-its-ai-health-play" tabindex="-1">⌚️ <strong><a href="https://blog.google/products-and-platforms/products/google-health/google-health-app/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Google folds Fitbit into its AI health play</a></strong> <a class="header-anchor" href="#⌚️-google-folds-fitbit-into-its-ai-health-play" aria-label="Permalink to &quot;⌚️ **[Google folds Fitbit into its AI health play](https://blog.google/products-and-platforms/products/google-health/google-health-app/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)**&quot;">​</a></h4><p>Image source: Google</p><p><strong>The Rundown:</strong> Google <a href="https://blog.google/products-and-platforms/products/google-health/google-health-app/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">opened</a> its AI health coach to the public after months in beta, integrating the Fitbit app into a new Google Health platform and pairing it with a new $99 screenless tracker that tracks and transmits body data to the AI.</p><p><strong>The details:</strong></p><ul><li><p>Running on Gemini, the AI coach can tailor weekly workout routines, interpret uploaded medical records, and ID what a user ate from a phone photo.</p></li><li><p>Google is consolidating the Fitbit app, Health Connect, Apple Health, wearable data, and U.S. medical records into a single Google Health hub.</p></li><li><p>The new $99 Fitbit Air has no screen and weighs just 12g, carrying heart rate, oxygen, and temperature sensors that provide body data to the AI coach.</p></li><li><p>Apple Watch, Garmin, and Oura owners are set to get AI coach access later this year, with Google opening it up to hardware outside of its own.</p></li></ul><p><strong>Why it matters:</strong> AI’s role in personal health is only growing, and integrating everything under one roof can help Google make the AI layer the core product while also owning a trusted wearable line that provides users with the personalized guidance and context typically missing from other trackers and less connected options.</p><h6 id="ai-training" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="✏️-test-multiple-ai-models-with-same-prompt" tabindex="-1">✏️ <a href="https://app.therundown.ai/guides/how-to-test-multiple-ai-models-with-the-same-prompt-fast?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">T</a><strong><a href="https://app.therundown.ai/guides/how-to-test-multiple-ai-models-with-the-same-prompt-fast?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">est multiple AI models with same prompt</a></strong> <a class="header-anchor" href="#✏️-test-multiple-ai-models-with-same-prompt" aria-label="Permalink to &quot;✏️ [T](https://app.therundown.ai/guides/how-to-test-multiple-ai-models-with-the-same-prompt-fast?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)**[est multiple AI models with same prompt](https://app.therundown.ai/guides/how-to-test-multiple-ai-models-with-the-same-prompt-fast?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/how-to-test-multiple-ai-models-with-the-same-prompt-fast?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to use OpenRouter Fusion to test the same prompt across multiple AI models at once. Instead of opening five apps and guessing, you can compare outputs side by side and build a quick cheat sheet for work.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Create an OpenRouter account, open <a href="https://openrouter.ai/labs/fusion?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">OpenRouter Fusion</a>, and pick how you want to pay for AI usage — OpenRouter credits or API keys you already pay for</p></li><li><p>In Fusion, pick the models you want to compare — we tested Opus 4.7 vs. GPT 5.4 vs. Grok — and run one benchmark prompt at a time, keeping it identical</p></li><li><p>Prompt something like: “You are advising a 20-person SaaS company deciding whether to replace its weekly status meeting with an async written update. Write a recommendation memo with 3 benefits, 3 risks, and a 2-week implementation plan. Keep it concise and practical”</p></li><li><p>Open the responses, read the side-by-side analysis, and note which model is strongest. In the demo, about 10 comparisons cost around 40 cents</p></li></ol><p><strong>Pro tip:</strong> Run a few prompts you use all the time, write which model wins each task, and use OpenRouter&#39;s model browser to compare price and speed before you spend more.</p><h6 id="presented-by-weights-biases" tabindex="-1">PRESENTED BY WEIGHTS &amp; BIASES <a class="header-anchor" href="#presented-by-weights-biases" aria-label="Permalink to &quot;PRESENTED BY WEIGHTS &amp; BIASES&quot;">​</a></h6><h4 id="🐝-new-guide-tools-and-workflows-to-develop-ai-agents" tabindex="-1">🐝****<a href="https://wandb.ai/site/resources/whitepapers/building-successful-ai-agents/?utm_source=rundown&amp;utm_medium=cpc&amp;utm_campaign=WP-AIAgentsPrimer&amp;utm_content=46150" target="_blank" rel="noreferrer"><strong>New guide: Tools and workflows to develop AI agents</strong></a> <a class="header-anchor" href="#🐝-new-guide-tools-and-workflows-to-develop-ai-agents" aria-label="Permalink to &quot;🐝****[**New guide: Tools and workflows to develop AI agents**](https://wandb.ai/site/resources/whitepapers/building-successful-ai-agents/?utm_source=rundown&amp;utm_medium=cpc&amp;utm_campaign=WP-AIAgentsPrimer&amp;utm_content=46150)&quot;">​</a></h4><p><a href="https://wandb.ai/site/resources/whitepapers/building-successful-ai-agents/?utm_source=rundown&amp;utm_medium=cpc&amp;utm_campaign=WP-AIAgentsPrimer&amp;utm_content=46150" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> AI agents can dramatically boost productivity and innovation, but getting them into the real world takes a lot of iteration. Whether you’re exploring agents for the first time or refining your current approach, this primer delivers actionable insights to help your team succeed and thrive in the AI era.</p><p><strong>Get the guide to learn:</strong></p><ul><li><p>What defines agentic applications and why observability matters</p></li><li><p>A proven workflow for building agentic AI applications</p></li><li><p>How pioneering companies are building and deploying AI agents today</p></li></ul><p><a href="https://wandb.ai/site/resources/whitepapers/building-successful-ai-agents/?utm_source=rundown&amp;utm_medium=cpc&amp;utm_campaign=WP-AIAgentsPrimer&amp;utm_content=46150" target="_blank" rel="noreferrer">Download a primer on building successful AI agents</a>.</p><h6 id="the-anthropic-institute" tabindex="-1">THE ANTHROPIC INSTITUTE <a class="header-anchor" href="#the-anthropic-institute" aria-label="Permalink to &quot;THE ANTHROPIC INSTITUTE&quot;">​</a></h6><h4 id="🔬-anthropic-plans-for-ai-that-builds-itself" tabindex="-1">🔬 <strong><a href="https://www.anthropic.com/research/anthropic-institute-agenda?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Anthropic plans for AI that builds itself</a></strong> <a class="header-anchor" href="#🔬-anthropic-plans-for-ai-that-builds-itself" aria-label="Permalink to &quot;🔬 **[Anthropic plans for AI that builds itself](https://www.anthropic.com/research/anthropic-institute-agenda?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)**&quot;">​</a></h4><p>Image source: Anthropic</p><p><strong>The Rundown:</strong> Anthropic&#39;s newly formed research arm, The Anthropic Institute, <a href="https://www.anthropic.com/research/anthropic-institute-agenda?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">published</a> its formal research agenda — a document that treats the possibility of AI systems improving themselves as something the company is actively preparing for.</p><p><strong>The details:</strong></p><ul><li><p>TAI sits inside Anthropic, letting researchers study Claude usage, internal workflows, and security signals before they hit the wider market.</p></li><li><p>The Institute’s agenda spans security threats, economic disruption, governance, and planning for self-improving models.</p></li><li><p>The team also proposed Cold War-style hotlines between labs and governments, plus &quot;fire drill&quot; exercises for sudden capability surges.</p></li><li><p>TAI said it is committed to publishing Economic Index data, monthly worker surveys, threat research, and more details on its own internal AI-boosted R&amp;D.</p></li></ul><p><strong>Why it matters:</strong> We <a href="https://www.rundown.ai/articles/ai-data-centers-head-for-the-ocean?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">wrote</a> earlier about Anthropic co-founder Jack Clark’s blog on self-improving systems, and TAI’s research agenda puts it very much into focus. Anthropic’s talk of “fire drills” and Cold War-style systems is to prepare for an “intelligence explosion” that we might be heading to faster than many expected.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)**&quot;">​</a></h3><ul><li><p>✈️ <a href="https://www.serko.ai/?utm_source=www.therundown.ai&amp;utm_medium=email&amp;utm_campaign=waitlist" target="_blank" rel="noreferrer">Serko.ai</a> - The AI travel assistant that plans, books, and manages your entire business trip, so you can skip the busywork*</p></li><li><p>🗣️ <a href="https://www.rundown.ai/tools/gpt-realtime-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">GPT-Realtime-2</a> - Voice AI that thinks, calls tools, maintains convo flow</p></li><li><p>🎥 <a href="https://www.rundown.ai/tools/elevenlabs-studio-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Studio Agent</a> - ElevenLabs&#39; AI editor to draft videos, places sound effects</p></li><li><p>🎆 <a href="https://x.ai/news/grok-imagine-quality-mode?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Grok Imagine Quality Mode</a> - xAI’s Image generation with higher realism</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today" tabindex="-1">📰 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Everything else in AI today</a></strong> <a class="header-anchor" href="#📰-everything-else-in-ai-today" aria-label="Permalink to &quot;📰 **[Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)**&quot;">​</a></h3><p><strong>Spotify</strong> <a href="https://newsroom.spotify.com/2026-05-07/personal-podcasts-launch/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">launched</a> ‘Personal Podcasts’, a tool allowing agents to turn items like briefings or class notes into a personal podcast directly inside users’ Spotify libraries.</p><p><strong>OpenAI</strong> <a href="https://openai.com/index/introducing-trusted-contact-in-chatgpt/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">introduced</a> Trusted Contact, an opt-in ChatGPT feature that alerts a designated friend or family member if signs of self-harm risk are detected.</p><p><strong>Scale AI</strong> <a href="https://www.bloomberg.com/news/articles/2026-05-06/meta-backed-scale-ai-wins-500-million-defense-department-deal?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">landed</a> a $500M Pentagon contract for military data analysis, marking a 5x jump from last September&#39;s $100M deal.</p><p><strong>Perplexity</strong><a href="https://x.com/perplexity_ai/status/2052445405754040816?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">rolled out</a> its Personal Computer to all Mac users, allowing it to take agentic action across a user’s local computer, files, and via the Comet browser.</p><p><strong>Mozilla</strong><a href="https://hacks.mozilla.org/2026/05/behind-the-scenes-hardening-firefox/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">published</a> a blog about using Claude Mythos Preview for security, saying the model patched more bugs in April than the past 15 months combined.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Tatiana B.</strong> in San Francisco, CA:</p><p>&quot;I&#39;m COO of a startup and mom to a two-and-a-half-year-old. Managing both is a lot, and keeping track of everything I need to do at home on top of work can be a real mental drain.</p><p>So I use AI to help me compile a document covering everything I need help with at home: my daughter&#39;s meal preferences, her daily routine, and house chores. I treat it like a work project, going back and forth with AI to think through what I actually need done, fill in gaps I hadn&#39;t thought of, and get it all out of my head into something I can hand to someone else.</p><p>Now, when someone new comes to help at home, I don&#39;t have to explain everything from scratch. That frees me up to actually be present with my daughter when I&#39;m with her, and focused on work when I&#39;m not. I also know I&#39;m lucky to be in a position to hire help, but using AI to think clearly about what you need and get it out of your head is something anybody can do.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/anthropic-spacex-ai-become-unlikely-compute-partners?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Anthropic, SpaceXAI become unlikely partners</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/gamestop-wild-bid-to-buy-ebay?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">GameStop’s wild bid to buy eBay</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/genesis-robot-makes-breakfast?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Genesis robot makes breakfast</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/how-to-test-multiple-ai-models-with-the-same-prompt-fast?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">Test multiple AI models with the same prompt, </a><a href="https://app.therundown.ai/guides/how-to-test-multiple-ai-models-with-the-same-prompt-fast?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-closes-reasoning-gap-in-voice-agents" target="_blank" rel="noreferrer">fast</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="anthropic-spacex-ai-become-unlikely-compute-partners" tabindex="-1"><a href="https://www.therundown.ai/p/anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Anthropic, SpaceX(AI) become unlikely compute partners</a> <a class="header-anchor" href="#anthropic-spacex-ai-become-unlikely-compute-partners" aria-label="Permalink to &quot;[Anthropic, SpaceX(AI) become unlikely compute partners](https://www.therundown.ai/p/anthropic-spacex-ai-become-unlikely-compute-partners)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-07</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=TGoD9zd88w5CaCK7EMH3pT4TG" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> Just months ago, Elon Musk was posting that Anthropic “hates Western Civilization” and should be renamed “Misanthropic”. Now, he’s renting them his entire Colossus 1 compute cluster.</p><p>The new deal pulls off three things at once: patching Claude&#39;s compute problems, hurting Musk&#39;s nemesis OAI by feeding its biggest rival, and signaling a new compute-landlord business for SpaceXAI even as Grok keeps chasing the frontier.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Anthropic, SpaceX partner in new compute deal</p></li><li><p>Mira Murati speaks out in Musk vs. OpenAI trial</p></li><li><p>Use Claude Design’s slide decks feature like a pro</p></li><li><p>DeepMind picks EVE Online game as next AI testbed</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="anthropic-spacex" tabindex="-1">ANTHROPIC &amp; SPACEX <a class="header-anchor" href="#anthropic-spacex" aria-label="Permalink to &quot;ANTHROPIC &amp; SPACEX&quot;">​</a></h6><h4 id="🔌-anthropic-spacex-ai-partner-in-new-compute-deal" tabindex="-1">🔌 <strong><a href="https://www.anthropic.com/news/higher-limits-spacex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Anthropic, SpaceX(AI) partner in new compute deal</a></strong> <a class="header-anchor" href="#🔌-anthropic-spacex-ai-partner-in-new-compute-deal" aria-label="Permalink to &quot;🔌 **[Anthropic, SpaceX(AI) partner in new compute deal](https://www.anthropic.com/news/higher-limits-spacex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> Anthropic just <a href="https://www.anthropic.com/news/higher-limits-spacex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">signed</a> a deal with SpaceX to lease its Colossus 1, raising Claude usage and putting Musk and Anthropic on one team months after he <a href="https://x.com/elonmusk/status/2027294561467613256?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">said</a> that Anthropic should be called “Misanthropic” and it &quot;hates Western Civilization.&quot;</p><p><strong>The details:</strong></p><ul><li><p>Anthropic will lease all of Colossus 1, a 300+ MW Memphis supercluster, with more than 220K Nvidia GPUs coming online within the month.</p></li><li><p>Anthropic said Claude Code’s 5-hour usage caps are now doubling across paid tiers, with additional increases via API and no more peak-hour restrictions.</p></li><li><p>Musk <a href="https://x.com/elonmusk/status/2052076315306864756?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">replied</a> on X that SpaceX will rent compute to “AI companies that are taking the right steps to ensure it is good for humanity.”</p></li><li><p>The Information also <a href="https://www.theinformation.com/articles/anthropic-commits-spending-200-billion-googles-cloud-chips?rc=a8sc5q&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">reported</a> yesterday that Anthropic is committing to a $200B, 5 GW compute deal over the next five years with Google Cloud.</p></li></ul><p><strong>Why it matters:</strong> This is a fascinating partnership from several angles. One being Musk taking the ‘enemy of my enemy is my friend’ approach — helping patch OAI’s biggest rival’s glaring compute hole. Another is SpaceXAI (<a href="https://x.com/elonmusk/status/2052105373621121284?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">apparently</a> the new name), moving to providing compute for rivals while still pushing to get Grok near the frontier.</p><h6 id="together-with-stripe" tabindex="-1">TOGETHER WITH STRIPE <a class="header-anchor" href="#together-with-stripe" aria-label="Permalink to &quot;TOGETHER WITH STRIPE&quot;">​</a></h6><h4 id="🏷️-a-five-step-framework-for-pricing-ai-products" tabindex="-1">🏷️ <a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=TGoD9zd88w5CaCK7EMH3pT4TG" target="_blank" rel="noreferrer"><strong>A five-step framework for pricing AI products</strong></a> <a class="header-anchor" href="#🏷️-a-five-step-framework-for-pricing-ai-products" aria-label="Permalink to &quot;🏷️ [**A five-step framework for pricing AI products**](https://stripe.com/lp/pricing-ai-products?utm_campaign=TGoD9zd88w5CaCK7EMH3pT4TG)&quot;">​</a></h4><p><a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=TGoD9zd88w5CaCK7EMH3pT4TG" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Pricing AI products means making a series of connected decisions—how you charge, how you match prices to value, and how you adapt as costs and the market shift. Stripe&#39;s new framework outlines 5 steps for pricing AI products.</p><p><strong>In this guide, you’ll learn:</strong></p><ul><li><p>How AI leaders like Anthropic, Clay, and Vercel approach their pricing</p></li><li><p>Strategies to align what you charge with the exact value you deliver</p></li><li><p>Steps to pick a pricing model that balances ease of user adoption with repeatable revenue</p></li></ul><p><strong><a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=TGoD9zd88w5CaCK7EMH3pT4TG" target="_blank" rel="noreferrer">Get the framework</a></strong>.</p><h6 id="elon-musk-vs-openai-trial" tabindex="-1">ELON MUSK VS. OPENAI TRIAL <a class="header-anchor" href="#elon-musk-vs-openai-trial" aria-label="Permalink to &quot;ELON MUSK VS. OPENAI TRIAL&quot;">​</a></h6><h4 id="🏛️-mira-murati-speaks-out-in-musk-vs-openai-trial" tabindex="-1">🏛️ <a href="https://www.theverge.com/ai-artificial-intelligence/925338/openai-musk-v-altman-mira-murati?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer"><strong>Mira Murati speaks out in Musk vs. OpenAI trial</strong></a> <a class="header-anchor" href="#🏛️-mira-murati-speaks-out-in-musk-vs-openai-trial" aria-label="Permalink to &quot;🏛️ [**Mira Murati speaks out in Musk vs. OpenAI trial**](https://www.theverge.com/ai-artificial-intelligence/925338/openai-musk-v-altman-mira-murati?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners)&quot;">​</a></h4><p>Image source: Reuters</p><p><strong>The Rundown:</strong> Ex-OpenAI CTO Mira Murati <a href="https://www.theverge.com/ai-artificial-intelligence/925338/openai-musk-v-altman-mira-murati?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">testified</a> Wednesday via video deposition in Elon Musk&#39;s lawsuit against OpenAI, accusing CEO Sam Altman of lying about a model&#39;s safety review, undermining her authority, and pitting execs against one another.</p><p><strong>The details:</strong></p><ul><li><p>Murati said Altman told her OAI&#39;s legal team cleared a model to skip safety review, which she later verified with counsel Jason Kwon was false.</p></li><li><p>She also described Altman giving conflicting directions to different execs, making her role as CTO harder and creating chaos across OAI&#39;s leadership.</p></li><li><p>Murati briefly became interim CEO during Altman’s 2023 firing, but said the board process put OpenAI “at risk of falling apart.”</p></li><li><p>Former OAI board member Helen Toner also <a href="https://nypost.com/2026/05/06/business/openai-ceo-sam-altman-was-dishonest-caused-chaos-ex-exec-mira-murati-says-in-bombshell-testimony/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">testified</a>, reportedly criticizing Murati as “afraid to stick her neck out” and scared of “blowback for her career”.</p></li></ul><p><strong>Why it matters:</strong> The 2023 board drama is the saga that will never conclude, and Murati’s testimony is a powerful voice to aid Musk’s argument that Altman and co. are untrustworthy. But whether that ultimately means anything related to Musk’s claims of Altman and Brockman “trying to steal a charity” in 2017 is up for the jury to decide.</p><h6 id="ai-training-1" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-1" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="👨‍💻-use-claude-design-s-slide-decks-feature-like-a-pro" tabindex="-1">👨‍💻 <strong><a href="https://app.therundown.ai/guides/use-claude-design-slide-decks-like-a-pro-with-this-strategy?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Use Claude Design’s slide decks feature like a pro</a></strong> <a class="header-anchor" href="#👨‍💻-use-claude-design-s-slide-decks-feature-like-a-pro" aria-label="Permalink to &quot;👨‍💻 **[Use Claude Design’s slide decks feature like a pro](https://app.therundown.ai/guides/use-claude-design-slide-decks-like-a-pro-with-this-strategy?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/use-claude-design-slide-decks-like-a-pro-with-this-strategy?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to use Claude Design to turn your raw data into a useful strategy deck complete with actual insights. Claude Design analyzes what is working and gives concrete recommendations your team can use.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Start with one CSV or spreadsheet with a messy report (YT channel data, Facebook ads, etc.) and decide what the deck needs to do (like find patterns)</p></li><li><p>Open claude.ai/design, choose Slide deck, skip the design system, toggle on speaker notes, and upload your data</p></li><li><p>Prompt: “Turn these files into a strategy deck on performance. Analyze the results by item and extract best practices from the data and assets. Use charts, rankings, and concrete recommendations. Match images or creative files to CSV using the filename or matching field. Keep it presentation-ready”</p></li><li><p>Generation will take 10-15 minutes. You can export to PowerPoint or Google Slides when it&#39;s ready</p></li></ol><p><strong>Pro tip:</strong> Duplicate the project and upload more data sources for Claude to incorporate into the presentation.</p><h6 id="presented-by-ibm" tabindex="-1">PRESENTED BY IBM <a class="header-anchor" href="#presented-by-ibm" aria-label="Permalink to &quot;PRESENTED BY IBM&quot;">​</a></h6><h4 id="🔌-rewire-the-c-suite-for-an-ai-first-world" tabindex="-1">🔌****<a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445612300&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer"><strong>Rewire the C-suite for an AI-first world</strong></a> <a class="header-anchor" href="#🔌-rewire-the-c-suite-for-an-ai-first-world" aria-label="Permalink to &quot;🔌****[**Rewire the C-suite for an AI-first world**](https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445612300&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners)&quot;">​</a></h4><p><a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445612300&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Most leaders know AI will reshape their business, but few have a clear playbook for how. An IBM Institute of Business Value analysis reveals 5 plays that CEOs must fulfill now for payoffs by 2030.</p><p><strong>To lead in an AI-first landscape, surveyed CEOs suggest:</strong></p><ul><li><p>Customize your AI mix, not just your AI models</p></li><li><p>Hire a Chief AI Officer if you haven’t already</p></li><li><p>Orchestrate intelligence —both artificial and human</p></li></ul><p><a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445612300&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Get deeper details in the 2026 CEO Study</a>.</p><h6 id="google-deepmind" tabindex="-1">GOOGLE DEEPMIND <a class="header-anchor" href="#google-deepmind" aria-label="Permalink to &quot;GOOGLE DEEPMIND&quot;">​</a></h6><h4 id="🛸-deepmind-picks-eve-online-game-as-next-ai-testbed" tabindex="-1">🛸 <strong><a href="https://www.ccpgames.com/news/2026/studio-behind-eve-online-goes-independent-rebrands-as-fenris-creations-enters-research-partnership-with-google-deepmind?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">DeepMind picks EVE Online game as next AI testbed</a></strong> <a class="header-anchor" href="#🛸-deepmind-picks-eve-online-game-as-next-ai-testbed" aria-label="Permalink to &quot;🛸 **[DeepMind picks EVE Online game as next AI testbed](https://www.ccpgames.com/news/2026/studio-behind-eve-online-goes-independent-rebrands-as-fenris-creations-enters-research-partnership-with-google-deepmind?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners)**&quot;">​</a></h4><p>Image source: Fenris Creations</p><p><strong>The Rundown:</strong> Google DeepMind <a href="https://www.ccpgames.com/news/2026/studio-behind-eve-online-goes-independent-rebrands-as-fenris-creations-enters-research-partnership-with-google-deepmind?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">picked up</a> a minority stake in Fenris Creations, a game studio spinoff from CCP Games, which makes the popular EVE Online — with DeepMind set to use the 23-year-old space game as a sandbox for AI research.</p><p><strong>The details:</strong></p><ul><li><p>EVE Online has run for two decades on a single server where players form corporations, set market prices, and torch six-figure fleets in day-long battles.</p></li><li><p>DeepMind&#39;s investment will come with AI agent runs on an offline EVE clone, testing how models reason over long timelines, retain memory, and learn.</p></li><li><p>Demis Hassabis cited Atari DQN, AlphaGo, AlphaStar, and SIMA as game-bred DeepMind wins, calling games “the perfect training ground” for AI algorithms.__</p></li><li><p>Fenris’ CEO pitched EVE as “one of the few environments” where intelligence can be tested “inside something that already behaves like a living world”.</p></li></ul><p><strong>Why it matters:</strong> DeepMind has been here before with Go, Atari, StarCraft, and SIMA, but EVE is not a match to win as much as a 23-year-old living, evolving society to understand. That makes the Fenris deal a natural next step in the shift from game-playing AI to agents that can operate inside less predictable real-life systems.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-1" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-1" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners)**&quot;">​</a></h3><ul><li><p>🧠 <a href="https://memoket.ai/pages/use-cases?utm_source=newsletter&amp;utm_medium=email&amp;utm_campaign=Rundown0507" target="_blank" rel="noreferrer">Memoket</a> - Stop briefing AI from scratch. Memoket captures conversations and remembers context. Try the app for free today*</p></li><li><p>🤖 <a href="https://www.rundown.ai/tools/claude-managed-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Claude Managed Agents</a> - Pre-built agent harness with ‘dreaming’ memory</p></li><li><p>⚡️ <a href="https://openai.com/index/gpt-5-5-instant/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">GPT 5.5 Instant</a> - OpenAI’s new default model across ChatGPT</p></li><li><p>🎧 <a href="https://www.rundown.ai/tools/realtime-tts-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Realtime TTS-2</a> - New voice AI that listens to match user tone and emotion</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today-1" tabindex="-1">📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Everything else in AI today</a> <a class="header-anchor" href="#📰-everything-else-in-ai-today-1" aria-label="Permalink to &quot;📰 [Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners)&quot;">​</a></h3><p><strong>Subquadratic</strong><a href="https://subq.ai/how-ssa-makes-long-context-practical?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">debuted</a> SubQ, a model the company claims has a 12M token context window and a 52x speed boost on long tasks at a fraction of the cost over rivals.</p><p><strong>Anthropic</strong> <a href="https://claude.com/blog/new-in-claude-managed-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">launched</a> dreaming, outcomes, and multi-agent orchestration for Managed Agents, letting agents study past sessions, grade work, and split complex jobs.</p><p><strong>OpenAI</strong> <a href="https://openai.com/index/mrc-supercomputer-networking/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">teamed</a> up with AMD, Intel, NVIDIA, Microsoft, and Broadcom to open-source MRC, a tool that keeps giant AI training runs going when hardware fails mid-session.</p><p><strong>Chinese AI startup DeepSeek</strong> is reportedly <a href="https://www.ft.com/content/daaf2e0a-4a0d-4d7c-a85b-445480f6b9c7?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">nearing</a> a new funding round that would value the company at as high as $45B.</p><p><strong>Google</strong><a href="https://blog.google/innovation-and-ai/models-and-research/google-labs/believe-flow-music-partnership/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">announced</a> a new partnership with TuneCore parent Believe to put its Flow Music and Lyria 3 Pro model in front of artists.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-1" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-1" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Anonymous</strong> :</p><p>&quot;I&#39;m recovering from a torn ACL, and my physiotherapist films all of my exercises and sends the videos to me on WhatsApp, narrating the sets/reps and notes on how to perform the exercise properly.</p><p>I uploaded the videos into Gemini and got it to build a prompt for Claude Code, which one-shotted an app that I now use to track sets, reps, weights from last workouts, notes, over multiple months. I can then export this data into a .csv for my physio before we check back in with each other.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-1" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-1" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/openai-ai-phone-just-jumped-the-line?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">OpenAI’s AI phone just jumped the line</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/gamestop-wild-bid-to-buy-ebay?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">GameStop’s wild bid to buy eBay</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meta-buys-a-humanoid-brain?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Meta buys a humanoid brain</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/use-claude-design-slide-decks-like-a-pro-with-this-strategy?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-spacex-ai-become-unlikely-compute-partners" target="_blank" rel="noreferrer">Use Claude Design’s slide decks feature like a pro</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="openai-s-ai-phone-just-jumped-the-line" tabindex="-1"><a href="https://www.therundown.ai/p/openai-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">OpenAI&#39;s AI phone just jumped the line</a> <a class="header-anchor" href="#openai-s-ai-phone-just-jumped-the-line" aria-label="Permalink to &quot;[OpenAI&#39;s AI phone just jumped the line](https://www.therundown.ai/p/openai-ai-phone-just-jumped-the-line)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-06</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://lambda.ai/llama-3-1-blackwell-mfu-benchmarks?utm_source=rundown-ai&amp;utm_medium=newsletter&amp;utm_campaign=2026-03-mfu-whitepaper&amp;utm_content=main-ad-may-6" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> Amid intensifying competition with Anthropic, improved models, and efforts to kill “side hustles,” OpenAI is apparently looking at something closer to home — an AI agent phone.</p><p>Analyst Ming-Chi Kuo says the company is fast-tracking this device for 2027, with some notable capabilities. Good news for those wanting a stronger AI experience in their pockets. The question is: where does this leave the ongoing work with Jony Ive? Or is this the same device?</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>OpenAI fast-tracks its ‘AI agent phone’</p></li><li><p>Anthropic’s AI agents for finance work</p></li><li><p>Make your Notion agents more autonomous</p></li><li><p>Home-based ‘mini’ AI data centers are coming</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="openai-1" tabindex="-1">OPENAI <a class="header-anchor" href="#openai-1" aria-label="Permalink to &quot;OPENAI&quot;">​</a></h6><h4 id="📱-openai-fast-tracks-ai-agent-phone" tabindex="-1">📱 <a href="https://x.com/mingchikuo/status/2051523855286776034?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer"><strong>OpenAI fast-tracks ‘AI agent phone’</strong></a> <a class="header-anchor" href="#📱-openai-fast-tracks-ai-agent-phone" aria-label="Permalink to &quot;📱 [**OpenAI fast-tracks ‘AI agent phone’**](https://x.com/mingchikuo/status/2051523855286776034?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line)&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> OpenAI is reportedly <a href="https://x.com/mingchikuo/status/2051523855286776034?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">accelerating</a> development of its first AI phone, now aiming for mass production in the first half of 2027, which is a full year earlier than previously reported, according to supply chain analyst Ming-Chi Kuo.</p><p><strong>The details:</strong></p><ul><li><p>Kuo says the timeline shift is likely driven by OAI’s IPO ambitions (strong hardware could strengthen investor pitch) and rising competition in AI phones.</p></li><li><p>The phone’s standout spec will be its image signal processor, with an enhanced HDR pipeline to improve AI agents’ real-world visual sensing.</p></li><li><p>MediaTek is positioned to be the sole chip supplier, with the device using two AI processors to handle vision and language tasks simultaneously.</p></li><li><p>Kuo also added that OpenAI’s combined 2027–28 shipments of this phone could touch 30M, if the development stays on track.</p></li></ul><p><strong>Why it matters:</strong> Controlling hardware and OS could be the key to a true agentic phone. But if OpenAI’s AI phone is closer than we thought, where does this leave the device it’s building with Jony Ive’s io? OpenAI <a href="https://www.therundown.ai/p/openai-jony-ive-join-forces-in-6-5b-acquisition?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">acquired</a> io last year with much fanfare to go “beyond screens,” but nothing concrete has appeared so far <a href="https://www.therundown.ai/p/what-openai-and-jony-ive-are-building?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">except a few rumors</a>.</p><h6 id="together-with-lambda" tabindex="-1">TOGETHER WITH LAMBDA <a class="header-anchor" href="#together-with-lambda" aria-label="Permalink to &quot;TOGETHER WITH LAMBDA&quot;">​</a></h6><h4 id="⚡-how-to-push-model-flops-utilization-past-50" tabindex="-1">⚡ <strong><a href="https://lambda.ai/llama-3-1-blackwell-mfu-benchmarks?utm_source=rundown-ai&amp;utm_medium=newsletter&amp;utm_campaign=2026-03-mfu-whitepaper&amp;utm_content=main-ad-may-6" target="_blank" rel="noreferrer">How to push Model FLOPS Utilization past 50%</a></strong> <a class="header-anchor" href="#⚡-how-to-push-model-flops-utilization-past-50" aria-label="Permalink to &quot;⚡ **[How to push Model FLOPS Utilization past 50%](https://lambda.ai/llama-3-1-blackwell-mfu-benchmarks?utm_source=rundown-ai&amp;utm_medium=newsletter&amp;utm_campaign=2026-03-mfu-whitepaper&amp;utm_content=main-ad-may-6)**&quot;">​</a></h4><p><a href="https://lambda.ai/llama-3-1-blackwell-mfu-benchmarks?utm_source=rundown-ai&amp;utm_medium=newsletter&amp;utm_campaign=2026-03-mfu-whitepaper&amp;utm_content=main-ad-may-6" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Most large-scale training runs operate at just 35–45% Model FLOPS Utilization, meaning teams pay for more than twice the compute they actually use. Lambda’s engineers benchmarked Llama 3.1 models from 8B to 405B on NVIDIA Blackwell GPUs to trace efficiency loss to its root causes.</p><p><strong>Efficiency losses were traced to:</strong></p><ul><li><p>Memory overhead capping effective throughput</p></li><li><p>Parallelism strategies misaligned with the hardware</p></li><li><p>Serialized communication stalling GPU cycles</p></li></ul><p><a href="https://lambda.ai/llama-3-1-blackwell-mfu-benchmarks?utm_source=rundown-ai&amp;utm_medium=newsletter&amp;utm_campaign=2026-03-mfu-whitepaper&amp;utm_content=main-ad-may-6" target="_blank" rel="noreferrer">Get the guide</a>.</p><h6 id="anthropic" tabindex="-1">ANTHROPIC <a class="header-anchor" href="#anthropic" aria-label="Permalink to &quot;ANTHROPIC&quot;">​</a></h6><h4 id="🤑-anthropic-s-ai-agents-for-finance-work" tabindex="-1">🤑 <a href="https://www.anthropic.com/news/finance-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer"><strong>Anthropic’s AI agents for finance work</strong></a> <a class="header-anchor" href="#🤑-anthropic-s-ai-agents-for-finance-work" aria-label="Permalink to &quot;🤑 [**Anthropic’s AI agents for finance work**](https://www.anthropic.com/news/finance-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line)&quot;">​</a></h4><p><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer"></a></p><p>Image source: Anthropic</p><p><strong>The Rundown:</strong> Anthropic just <a href="https://www.anthropic.com/news/finance-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">unveiled</a> 10 ready-to-run AI agents aimed squarely at financial services and insurance — capable of handling work ranging from building pitchbooks and screening KYC files to reviewing earnings and valuations.</p><p><strong>The details:</strong></p><ul><li><p>Each agent comes with task-specific domain skills and instructions, connectors to relevant data sources, and add-on Claude models for sub-tasks.</p></li><li><p>Firms can adapt any agent of their choice to their own modeling conventions, risk policies, and approval flows — while staying in the loop 24/7.</p></li><li><p>The agents can be used as plugins within Claude Cowork or Claude Code on desktop, or as cookbooks, running as Managed Agents on the Claude platform.</p></li><li><p>Claude is also getting an add-in for Microsoft 365 as well as data connectors from Dun &amp; Bradstreet, Verisk, IBISWorld, and other financial services partners.</p></li></ul><p><strong>Why it matters:</strong> Development, <a href="https://www.anthropic.com/news/claude-code-security?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">cybersecurity</a>, <a href="https://www.therundown.ai/p/claude-comes-for-the-design-stack?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">design</a>, and now finance. Anthropic is going domain by domain, meeting businesses where they are instead of selling a general model and letting them figure it out. Its <a href="https://www.anthropic.com/news/enterprise-ai-services-company?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">new $1.5B joint venture</a> alongside Wall Street giants reinforces this strategy, further fueling its race with OpenAI.</p><h6 id="ai-training-2" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-2" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="🤖-make-your-notion-agents-more-autonomous" tabindex="-1">🤖 <strong><a href="https://app.therundown.ai/guides/use-this-hidden-feature-to-make-your-notion-agents-autonomous?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Make your Notion agents more autonomous</a></strong> <a class="header-anchor" href="#🤖-make-your-notion-agents-more-autonomous" aria-label="Permalink to &quot;🤖 **[Make your Notion agents more autonomous](https://app.therundown.ai/guides/use-this-hidden-feature-to-make-your-notion-agents-autonomous?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/use-this-hidden-feature-to-make-your-notion-agents-autonomous?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn a hidden workflow that will make your Notion Agents more autonomous and powerful than they are by default. This lets you wake up any agent, give it tasks, and then get a report on what it did.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Create a Notion agent from the “Agents” option in the sidebar. Then, open a database for the agent’s prompt and task reports. Ours is called “reports”</p></li><li><p>Click the New dropdown, open Templates, and create a @Today template (ours was Daily Summary). @Today makes duplicates inherit the current date</p></li><li><p>Set the properties, write task instructions in the page body, and @ mention the agent, so the duplicate triggers it. Remember to stop the agent when doing this, so it doesn’t overwrite the template</p></li><li><p>From the template, click New template, then Duplicate, and pick a cadence. We run ours daily at 7 a.m. A small blue icon next to the template shows it’s live</p></li></ol><p><strong>Pro tip:</strong> Try setting up daily debriefs, weekly reports, and email automations. Now you can route them all through the same planning agent.</p><h6 id="presented-by-ibm-1" tabindex="-1">PRESENTED BY IBM <a class="header-anchor" href="#presented-by-ibm-1" aria-label="Permalink to &quot;PRESENTED BY IBM&quot;">​</a></h6><h4 id="🔌-rewire-the-c-suite-for-an-ai-first-world-1" tabindex="-1">🔌 <strong><a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445741634&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Rewire the C-suite for an AI-first world</a></strong> <a class="header-anchor" href="#🔌-rewire-the-c-suite-for-an-ai-first-world-1" aria-label="Permalink to &quot;🔌 **[Rewire the C-suite for an AI-first world](https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445741634&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line)**&quot;">​</a></h4><p><a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445741634&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Most leaders know AI will reshape their business, but few have a clear playbook for how. An IBM Institute of Business Value analysis reveals 5 plays that CEOs must fulfill now for payoffs by 2030.</p><p><strong>To lead in an AI-first landscape, surveyed CEOs suggest:</strong></p><ul><li><p>Customize your AI mix, not just your AI models</p></li><li><p>Hire a Chief AI Officer if you haven’t already</p></li><li><p>Orchestrate intelligence — both artificial and human</p></li></ul><p><a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445741634&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Get deeper details in the 2026 CEO Study</a>.</p><h6 id="ai-data-centers" tabindex="-1">AI DATA CENTERS <a class="header-anchor" href="#ai-data-centers" aria-label="Permalink to &quot;AI DATA CENTERS&quot;">​</a></h6><h4 id="🏘️-home-based-mini-ai-data-centers-are-coming" tabindex="-1">🏘️ <a href="https://www.businesswire.com/news/home/20260414372626/en/SPAN-Announces-XFRA-a-Distributed-Data-Center-Solution-to-Close-the-Speed-to-Power-Gap-for-AI-Compute-Demand?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer"><strong>Home-based ‘mini’ AI data centers are coming</strong></a> <a class="header-anchor" href="#🏘️-home-based-mini-ai-data-centers-are-coming" aria-label="Permalink to &quot;🏘️ [**Home-based ‘mini’ AI data centers are coming**](https://www.businesswire.com/news/home/20260414372626/en/SPAN-Announces-XFRA-a-Distributed-Data-Center-Solution-to-Close-the-Speed-to-Power-Gap-for-AI-Compute-Demand?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line)&quot;">​</a></h4><p>Image source: Span</p><p><strong>The Rundown:</strong> California startup Span is <a href="https://www.businesswire.com/news/home/20260414372626/en/SPAN-Announces-XFRA-a-Distributed-Data-Center-Solution-to-Close-the-Speed-to-Power-Gap-for-AI-Compute-Demand?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">teaming up</a> with Nvidia to install mini AI data centers on the walls of residential homes and small businesses, tapping unused electrical capacity on local grids to meet surging AI compute demand.</p><p><strong>The details:</strong></p><ul><li><p>Span has developed XFRA, small compute nodes that mount on the exterior walls of homes, alongside accompanying HVAC and electrical systems.</p></li><li><p>Nvidia is providing its liquid-cooled RTX PRO 6000 Blackwell Server Edition GPUs to power each XFRA box, ensuring noiseless computing for AI workloads.</p></li><li><p>Span told <a href="https://www.cnbc.com/2026/05/05/nvidia-pulte-span-mini-data-centers-on-homes.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">CNBC</a> it can install 8,000 XFRA units 6x faster and at one-fifth the cost of building a comparable 100MW centralized data center facility.</p></li><li><p>Currently, the company is working with PulteGroup, one of the largest U.S. homebuilders, to test the box and its economics in newly built communities.</p></li></ul><p><strong>Why it matters:</strong> Grid strain from data centers is real, and Span’s boxes could spread the load while tapping only unused capacity. But public response is an open question — not all will love the idea of a data center box mounted where kids play, especially when alternatives like <a href="https://www.rundown.ai/articles/ai-data-centers-head-for-the-ocean?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">ocean</a>- and <a href="https://www.rundown.ai/articles/googles-ai-space-moonshot?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">space-based</a> data centers are also in sight.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-2" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-2" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line)**&quot;">​</a></h3><ul><li><p>🚀 <a href="https://blog.box.com/introducing-box-automate-ai-powered-workflow-orchestration?utm_source=newsletter&amp;utm_medium=paidinfluencer&amp;utm_theme=icm&amp;utm_campaign=FY27_Q2_RundownAI_AutomateNewTool" target="_blank" rel="noreferrer"><strong>Box Automate</strong></a> - Orchestrate agentic workflow automation, securely and at scale*</p></li><li><p>🎨 <a href="https://www.rundown.ai/tools/pomelli?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Pomelli</a> - Make product-specific campaigns with Google’s AI marketing tool</p></li><li><p>🖼️ <a href="https://lumalabs.ai/api?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Uni 1.1</a> - Luma’s new image generation and editing AI that nears the frontier</p></li><li><p>🎮️ <a href="https://www.astrocade.com/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Astrocade</a> - Platform to create shareable games with AI</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today-2" tabindex="-1">📰 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Everything else in AI today</a></strong> <a class="header-anchor" href="#📰-everything-else-in-ai-today-2" aria-label="Permalink to &quot;📰 **[Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line)**&quot;">​</a></h3><p><strong>OpenAI’s</strong> GPT-5.5-Instant <a href="https://openai.com/index/gpt-5-5-instant/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">started</a> rolling out to all ChatGPT users, bringing improved performance, stronger memory, and more personalized, concise responses.</p><p><strong>Microsoft</strong> <a href="https://www.microsoft.com/en-us/microsoft-365/blog/2026/05/05/copilot-cowork-from-conversation-to-action-across-skills-integrations-and-devices/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">expanded</a> its Copilot Cowork agentic system to iOS and Android, while adding built-in skills for common tasks and data plugins for business systems.</p><p><strong>Apple</strong> <a href="https://www.bbc.com/news/articles/c0j2nydnzy7o?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">agreed</a> to pay some U.S. iPhone buyers a collective $250M to settle a class action lawsuit over misleading claims about its new AI Siri, but admitted no wrongdoing.</p><p><strong>Perplexity AI</strong> <a href="https://x.com/perplexity_ai/status/2051693893473935372?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">launched</a> Computer for Professional Finance, bringing licensed data and 35 dedicated workflows to its agentic system to help analysts handle routine work.</p><p><strong>Anthropic</strong> reportedly <a href="https://www.theinformation.com/articles/anthropic-commits-spending-200-billion-googles-cloud-chips?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">committed</a> to spending $200B on Google’s cloud and chips over the next five years, now making 40%+ of Google’s revenue backlog.</p><p><strong>Coinbase</strong> CEO Brian Armstrong <a href="https://x.com/brian_armstrong/status/2051616759145185723?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">said</a> the company is cutting 14% of its workforce, ~700 people, as it shifts to AI-native teams, agent-driven workflows, and leaner ops.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-2" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-2" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Schy W.</strong> in Springfield, IL:</p><p>&quot;I went to a music festival — multiple stages, music over several days. Many bands had more than one set time/location. I fed Claude the festival’s schedule PDF and told it to extract the information, but to ignore autograph signing and music workshops. I then read off a list of bands I wanted to see and followed up with a subset of those that I absolutely did not want to miss. I requested a schedule that would plan out where I should be to maximize the number of bands I could reasonably see with a simple prompt.</p><p>It understood the mission and in one stroke produced a fantastic spreadsheet optimizing my time and noting my priorities, stages, times, partial sets, if a band has another set, and explained the decision-making rationale.”</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-2" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-2" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.therundown.ai/p/ai-data-centers-head-for-the-ocean?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">AI data centers head for the ocean</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/gamestop-wild-bid-to-buy-ebay?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">GameStop&#39;s wild bid to buy eBay</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meta-buys-a-humanoid-brain?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Meta buys a humanoid brain</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/use-this-hidden-feature-to-make-your-notion-agents-autonomous?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Make your Notion agents more autonomous</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="ai-data-centers-head-for-the-ocean" tabindex="-1"><a href="https://www.therundown.ai/p/ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">AI data centers head for the ocean</a> <a class="header-anchor" href="#ai-data-centers-head-for-the-ocean" aria-label="Permalink to &quot;[AI data centers head for the ocean](https://www.therundown.ai/p/ai-data-centers-head-for-the-ocean)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-05</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> AI&#39;s land grab is running into walls — literal ones, in the form of an angry public fed up with data center constructions in their cities.</p><p>Oregon-based startup Panthalassa is taking things offshore instead, with Peter Thiel leading a new $140M round for floating structures that turn ocean energy into the compute AI companies are all scrambling for more of.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Thiel-backed startup brings AI data centers to sea</p></li><li><p>Anthropic co-founder forecasts AI’s self-building era</p></li><li><p>How to replace Siri with a free local model</p></li><li><p>OAI, Anthropic launching rival private equity ventures</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="peter-thiel-panthalassa" tabindex="-1">PETER THIEL &amp; PANTHALASSA <a class="header-anchor" href="#peter-thiel-panthalassa" aria-label="Permalink to &quot;PETER THIEL &amp; PANTHALASSA&quot;">​</a></h6><h4 id="🌊-thiel-backed-startup-brings-ai-data-centers-to-sea" tabindex="-1">🌊 <a href="https://www.businesswire.com/news/home/20260504552400/en/Panthalassa-Raises-%24140-Million-to-Power-AI-at-Sea?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer"><strong>Thiel-backed startup brings AI data centers to sea</strong></a> <a class="header-anchor" href="#🌊-thiel-backed-startup-brings-ai-data-centers-to-sea" aria-label="Permalink to &quot;🌊 [**Thiel-backed startup brings AI data centers to sea**](https://www.businesswire.com/news/home/20260504552400/en/Panthalassa-Raises-%24140-Million-to-Power-AI-at-Sea?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean)&quot;">​</a></h4><p>Image source: Panthalassa</p><p><strong>The Rundown:</strong> PayPal and Palantir founder Peter Thiel just <a href="https://www.businesswire.com/news/home/20260504552400/en/Panthalassa-Raises-%24140-Million-to-Power-AI-at-Sea?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">led</a> a $140M Series B for Panthalassa, an Oregon-based startup that builds autonomous floating compute structures powered by ocean waves — reportedly valuing the company at nearly $1B.</p><p><strong>The details:</strong></p><ul><li><p>Each 85-meter steel node bobs in open ocean, converting wave motion into electricity for onboard AI chips, all cooled naturally by seawater.</p></li><li><p>Once deployed, the nodes can steer themselves to remote waters using only their hull shape (no engines) and beam AI results back via SpaceX’s Starlink.</p></li><li><p>The raise will finish a pilot factory near Portland and deploy the first wave-powered compute nodes in the Pacific Ocean, with commercial rollout in 2027.</p></li><li><p>Thiel <a href="https://www.ft.com/content/711ce313-16fb-4a12-b6be-fbed547c8a39?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">told</a> the Financial Times that “extraterrestrial solutions (to compute) are no longer science fiction” and that “Panthalassa has opened the ocean frontier.”</p></li></ul><p><strong>Why it matters:</strong> AI data centers have been one of the more controversial AI talking points for the general public, and the hostility towards their construction is growing fast. While both Elon Musk and Google have pushed space-based options, those are still far from reality, making the ocean an interesting and more realistic alternative.</p><h6 id="together-with-you-com" tabindex="-1">TOGETHER WITH YOU.COM <a class="header-anchor" href="#together-with-you-com" aria-label="Permalink to &quot;TOGETHER WITH YOU.COM&quot;">​</a></h6><h4 id="⏰-api-latency-is-only-part-of-the-story" tabindex="-1">⏰****<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer"><strong>API latency is only part of the story</strong></a> <a class="header-anchor" href="#⏰-api-latency-is-only-part-of-the-story" aria-label="Permalink to &quot;⏰****[**API latency is only part of the story**](https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26)&quot;">​</a></h4><p><a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Most teams pick an API by checking a benchmark table and calling it done—a shortcut that could miss what really matters in production. This guide from <a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer">You.com</a> explains why raw latency is a misleading signal and what to measure instead.</p><p><strong>What you&#39;ll learn:</strong></p><ul><li><p>Why p50 latency hides the failures your users actually experience</p></li><li><p>The &quot;time-to-useful-result&quot; framework that captures what benchmarks leave out</p></li><li><p>Four hidden cost drivers that show up in your logs, not vendor tables</p></li><li><p>How to evaluate APIs at your actual concurrency levels, not the demo conditions</p></li></ul><p>Learn what to measure instead. <a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer">Download the guide</a>.</p><h6 id="anthropic-1" tabindex="-1">ANTHROPIC <a class="header-anchor" href="#anthropic-1" aria-label="Permalink to &quot;ANTHROPIC&quot;">​</a></h6><h4 id="📝-anthropic-co-founder-forecasts-ai-s-self-building-era" tabindex="-1">📝 <strong><a href="https://importai.substack.com/p/import-ai-455-automating-ai-research?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Anthropic co-founder forecasts AI’s self-building era</a></strong> <a class="header-anchor" href="#📝-anthropic-co-founder-forecasts-ai-s-self-building-era" aria-label="Permalink to &quot;📝 **[Anthropic co-founder forecasts AI’s self-building era](https://importai.substack.com/p/import-ai-455-automating-ai-research?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean)**&quot;">​</a></h4><p>Image source: Jack Clark (@JackclarkSF on X) / The Rundown</p><p><strong>The Rundown:</strong> Anthropic co-founder Jack Clark <a href="https://importai.substack.com/p/import-ai-455-automating-ai-research?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">published</a> a new blog post on self-improving AI, putting 60%+ odds on AI systems training their own successors before 2029, citing public data showing AI is already handling a range of core R&amp;D tasks.</p><p><strong>The details:</strong></p><ul><li><p>Clark built the case on public papers and benchmark data, charting AI going from near-zero to 100% across core development tasks in under 3 years.</p></li><li><p>METR <a href="https://metr.org/time-horizons/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">data</a> shows AI’s independent work capability went from 30-second tasks in 2022 to 12 hours in 2026, with 100-hour runs projected by year-end.</p></li><li><p>Clark also pointed to the SWE-Bench benchmark (real GitHub coding), moving from Claude 2 at 2% to Mythos Preview at 93.9% in under three years.</p></li><li><p>OpenAI is also <a href="https://x.com/sama/status/1983584366547829073?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">targeting</a> an automated research intern by Sept. 2026, while startups like Recursive Superintelligence share similar self-improvement goals.</p></li></ul><p><strong>Why it matters:</strong> Self-improving AI systems feel like the inflection point that really makes model development go exponential, and “by the end of 2028” is not that far away. AI is already moving at a speed that is hard for most to process — but once it can reliably build and train itself, all bets are off for how fast things can truly move.</p><h6 id="ai-training-3" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-3" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="📲-how-to-replace-siri-with-a-free-local-model" tabindex="-1">📲****<a href="https://app.therundown.ai/guides/how-to-replace-siri-with-a-free-local-model?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer"><strong>How to replace Siri with a free local model</strong></a> <a class="header-anchor" href="#📲-how-to-replace-siri-with-a-free-local-model" aria-label="Permalink to &quot;📲****[**How to replace Siri with a free local model**](https://app.therundown.ai/guides/how-to-replace-siri-with-a-free-local-model?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean)&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/how-to-replace-siri-with-a-free-local-model?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to download a free AI model to your iPhone and bind it to your phone&#39;s action button like Siri. The model is installed locally, so you will be able to use it without the internet or sending out your private data.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Download <a href="https://apps.apple.com/us/app/locally-ai-local-ai-chat/id6741426692?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Locally AI</a> from the App Store, choose your model. You can start with Google’s new, open-source Gemma model, which typically works great</p></li><li><p>Download the AI and keep the app open. Now, open settings, search for Action Button, swipe to the Shortcut option, search Locally AI, and choose Voice Mode</p></li><li><p>Press the Action Button on your iPhone and wait for the chime. The app will ask you to download a speech-to-text model the first time. Download it</p></li><li><p>Now try asking the model a question. We found they are best for explaining concepts, translation tasks, and math</p></li></ol><p><strong>Pro tip:</strong> Download a bigger model and run the same prompt through it. Compare speed, storage size, and answer quality to get the perfect AI for your iPhone.</p><h6 id="ai-the-enterprise" tabindex="-1">AI &amp; THE ENTERPRISE <a class="header-anchor" href="#ai-the-enterprise" aria-label="Permalink to &quot;AI &amp; THE ENTERPRISE&quot;">​</a></h6><h4 id="💰-oai-anthropic-launching-rival-private-equity-ventures" tabindex="-1">💰 <strong><a href="https://www.anthropic.com/news/enterprise-ai-services-company?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">OAI, Anthropic launching rival private equity ventures</a></strong> <a class="header-anchor" href="#💰-oai-anthropic-launching-rival-private-equity-ventures" aria-label="Permalink to &quot;💰 **[OAI, Anthropic launching rival private equity ventures](https://www.anthropic.com/news/enterprise-ai-services-company?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> Anthropic <a href="https://www.anthropic.com/news/enterprise-ai-services-company?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">announced</a> the formation of a new Claude services company with Blackstone, Hellman &amp; Friedman, and Goldman Sachs, with OpenAI also reportedly <a href="https://finance.yahoo.com/sectors/technology/articles/openai-finalizes-10-billion-joint-123100557.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">raising</a> for its own PE-backed ‘Deployment Company’ the same day.</p><p><strong>The details:</strong></p><ul><li><p>The $1.5B Anthropic venture will focus on mid-sized companies, pairing its Applied AI engineers with teams building custom Claude workflows.</p></li><li><p>OAI&#39;s &quot;Deployment Company&quot; will reportedly bring in $4B from 19 investors at a $10B valuation, including TPG, Brookfield, Bain, and SoftBank.</p></li><li><p>Both models would give the frontier AI labs direct paths into portfolio companies that often lack the in-house talent to deploy AI systems alone.</p></li></ul><p><strong>Why it matters:</strong> The barriers for companies aren’t the models anymore, but actually getting it installed and integrated into messy, large-scale businesses. These paths look more like frontier labs creating their own AI-native consulting firms, with a wealth of private equity portfolio companies ready to get in on the action.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-3" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-3" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean)**&quot;">​</a></h3><ul><li><p>🗣️ <a href="https://www.unwrap.ai/product-product-operations-ai-product?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Unwrap Customer Intelligence</a> - Get AI-driven insights from your unstructured customer feedback to build your product roadmap*</p></li><li><p>🚀 <a href="https://www.rundown.ai/tools/grok-4-3?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Grok 4.3</a> - xAI’s AI with strong cost efficiency, domain-specific performance</p></li><li><p>🤖 <a href="https://www.rundown.ai/tools/cofounder-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Cofounder 2</a> - General Intelligence&#39;s new agent orchestrator for businesses</p></li><li><p>🦮 <a href="https://www.rundown.ai/tools/codex-pets?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Codex Pets</a> - OpenAI&#39;s animated companions for tracking Codex work</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today-3" tabindex="-1">📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Everything else in AI today</a> <a class="header-anchor" href="#📰-everything-else-in-ai-today-3" aria-label="Permalink to &quot;📰 [Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean)&quot;">​</a></h3><p><strong>A new filing in the Elon Musk vs. OpenAI case</strong><a href="https://www.cnbc.com/2026/05/04/musk-altman-open-ai-settlement-trial-brockman.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">showed</a> that Musk reached out to OAI President Greg Brockman about a potential settlement days before the trial.</p><p><strong>The New York Times</strong> <a href="https://www.nytimes.com/2026/05/04/technology/trump-ai-models.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">reported</a> that the White House is seeking to create a formal review and oversight process prior to companies publicly deploying AI models.</p><p><strong>Sierra</strong> <a href="https://sierra.ai/blog/better-customer-experiences-built-on-sierra?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">raised</a> $950M at a $15B valuation, with the platform saying it now serves over 40% of the Fortune 50 companies for AI-driven customer experiences.</p><p><strong>Roomba creator and former iRobot CEO Colin Angle</strong> <a href="https://apnews.com/article/ai-pet-robot-familiar-machines-irobot-roomba-da873ddff1ebcc95f793852b8e53d2d2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">introduced</a> the Familiar, a bulldog-sized AI pet robot targeting retirees who&#39;ve aged out of pet ownership.</p><p><strong>Anthropic is reportedly in talks</strong> to <a href="https://www.theinformation.com/articles/anthropic-talks-buy-ai-chips-u-k-startup?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">purchase</a>**** chips from Fractile, a three-year-old London startup focused on more efficient chips for running AI models.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-3" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-3" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Adam M.</strong> in Berlin, Germany:</p><p>My best friend Eric was in a horse riding accident, which has left him partially paralyzed from the neck down. His medical insurance would only cover some of it. He was in a remote place in South Africa, so he needed to be flown by helicopter to the nearest hospital and then undergo multiple surgeries.</p><p>We used AI to help us set up the GoFundMe page and create social media posts for him, and to manage his ongoing recovery. Given that he can&#39;t really use his hands, he&#39;s able to use his phone now with AI to give updates and share about his journey with the world so that we can get the message out there to help him recover.</p><p>We&#39;re also using it to stay up to date with GoFundMe and their documentation and what they need to prove that he&#39;s a real person and that it isn&#39;t a scam. Whenever they send requests, we can paste them into Claude and get a properly formatted answer back so they can speed up the approval process, release their funds, and make sure they&#39;re happy.</p><p>It also helped us estimate what we should do in terms of a goal. We&#39;ve set the goal at half a million euros, and we are well on the way.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-3" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-3" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/ai-shows-its-skills-in-the-emergency-room?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">AI shows its skills in the emergency room</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/spacex-rocket-to-crash-into-the-moon?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">SpaceX is about to crash into the Moon</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meta-buys-a-humanoid-brain?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Meta buys a humanoid brain</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/how-to-replace-siri-with-a-free-local-model?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">How to replace Siri with a free local model</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="ai-shows-its-skills-in-the-emergency-room" tabindex="-1"><a href="https://www.therundown.ai/p/ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">AI shows its skills in the emergency room</a> <a class="header-anchor" href="#ai-shows-its-skills-in-the-emergency-room" aria-label="Permalink to &quot;[AI shows its skills in the emergency room](https://www.therundown.ai/p/ai-shows-its-skills-in-the-emergency-room)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-04</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> AI just beat two attending emergency room physicians across real patient cases in a new Harvard study. The model? OpenAI’s o1-preview, released in… 2024.</p><p>Millions of users are already turning to ChatGPT for health advice every day, but the data shows that AI models (preferably not several generations behind) may be ready for a more formal seat in the exam room alongside the doctor as well.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Old AI model tops doctors in ER trial</p></li><li><p>The Rundown Roundtable: Our AI use cases</p></li><li><p>Create converting landing pages in Claude</p></li><li><p>Pentagon announces new AI partners</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="openai-2" tabindex="-1">OPENAI <a class="header-anchor" href="#openai-2" aria-label="Permalink to &quot;OPENAI&quot;">​</a></h6><h4 id="🏥-old-ai-model-tops-doctors-in-er-trial" tabindex="-1">🏥 <strong><a href="https://www.harvardmagazine.com/ai/ai-outperforms-doctors-diagnosis-harvard-study?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Old AI model tops doctors in ER trial</a></strong> <a class="header-anchor" href="#🏥-old-ai-model-tops-doctors-in-er-trial" aria-label="Permalink to &quot;🏥 **[Old AI model tops doctors in ER trial](https://www.harvardmagazine.com/ai/ai-outperforms-doctors-diagnosis-harvard-study?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> A Harvard study <a href="https://www.science.org/doi/10.1126/science.adz4433?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">published</a> in Science just put OpenAI&#39;s o1-preview (released in 2024) through 76 real ER cases, with the AI diagnosing patients more accurately than two physicians, despite using only raw electronic health-record text.</p><p><strong>The details:</strong></p><ul><li><p>The study compared OpenAI&#39;s o1-preview model with two attending physicians across 76 real ER cases and three decision stages of patient care.</p></li><li><p>At initial ER triage, the model gave the correct diagnosis 67.1% of the time, compared to 55.3% and 50.0% for the two physicians.</p></li><li><p>The two separate physician reviewers tasked with scoring couldn&#39;t tell which diagnoses came from the model and which came from the humans.</p></li><li><p>In one case, the AI <a href="https://www.sciencenews.org/article/ai-help-doctors-help-diagnoses?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">flagged</a> a rare flesh-eating infection in a transplant patient roughly 12 to 24 hours before the treating doctor caught it.</p></li></ul><p><strong>Why it matters:</strong> Millions of people are already using AI daily for health questions, but studies like these are showing the usefulness can also flow the other way to the doctors themselves. If a model generations behind is already beating ER doctors, imagine what the frontier could look like inside the patient care process.</p><h6 id="together-with-unwrap" tabindex="-1">TOGETHER WITH UNWRAP <a class="header-anchor" href="#together-with-unwrap" aria-label="Permalink to &quot;TOGETHER WITH UNWRAP&quot;">​</a></h6><h4 id="⚡️-see-how-oura-automates-customer-feedback-analysis" tabindex="-1">⚡️ <a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"><strong>See how Oura automates customer feedback analysis</strong></a> <a class="header-anchor" href="#⚡️-see-how-oura-automates-customer-feedback-analysis" aria-label="Permalink to &quot;⚡️ [**See how Oura automates customer feedback analysis**](https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)&quot;">​</a></h4><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Unwrap’s customer intelligence platform that pulls all your feedback – surveys, reviews, support tickets, social comments– into one view, then uses AI to surface the most actionable insights to deliver them to your inbox. Teams at Perplexity, Stripe and DoorDash rely on Unwrap to ensure no customer voice gets lost.</p><p><strong>With Unwrap you get:</strong></p><ul><li><p>All customer feedback automatically categorized</p></li><li><p>Query feedback using Unwrap Assistant, or in your favorite tools using Unwrap&#39;s MCP</p></li><li><p>Real-time alerts from feedback as they arise</p></li><li><p>A clear view of customer sentiment</p></li></ul><p>Unwrap is offering a trial of its tools to Rundown AI subscribers! <a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Grab 15 minutes with the team to get set up</a>.</p><h6 id="the-rundown-roundtable" tabindex="-1">THE RUNDOWN ROUNDTABLE <a class="header-anchor" href="#the-rundown-roundtable" aria-label="Permalink to &quot;THE RUNDOWN ROUNDTABLE&quot;">​</a></h6><h4 id="💡-the-rundown-roundtable-our-ai-use-cases" tabindex="-1">💡 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">The Rundown Roundtable: Our AI use cases</a></strong> <a class="header-anchor" href="#💡-the-rundown-roundtable-our-ai-use-cases" aria-label="Permalink to &quot;💡 **[The Rundown Roundtable: Our AI use cases](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)**&quot;">​</a></h4><p><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p>Image source: Ideogram / The Rundown</p><p><strong>The Rundown:</strong> The Rundown Roundtable is a weekly feature where we poll members of The Rundown staff about how we use AI in our work and daily lives.</p><p>**Jennifer, Tech &amp; Robotics Writer: **Last year, my daughter was diagnosed with a rare autoimmune disease. Like any parent in that situation, I wanted to understand everything I could so we could make the best decisions for her care. I used both Gemini and ChatGPT to help me sort through the medical literature, treatment options, possible side effects, and how other countries approach treatment.</p><p>I also turned to ChatGPT to identify the leading specialists in the country — thankfully, our referred doctor turned out to be one of them, which gave us even more reassurance. More than anything, it helped demystify the disease and make us feel confident that we were doing everything we could. She’s doing really well on her medications, and seeing her recover has been an enormous relief.</p><p><strong>Shubham, Editor:</strong> I use ChatGPT as a label-reading filter for packaged snacks, uploading product photos and asking it to flag hidden sugars, oils like palm, and preservatives, then compare options against a strict checklist of clean ingredients, minimal processing, and decent macros.</p><p>It’s especially useful for decoding lesser-known, jargon-heavy terms on the back label, translating things like INS numbers, stabilizers, and emulsifiers into plain English so it’s clear what’s actually being consumed. Instead of trusting front-of-pack claims like “multigrain” or “sugar-free,” it breaks down what’s inside, surfaces trade-offs, and narrows choices to the best options available online</p><h6 id="ai-training-4" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-4" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="🎨-design-converting-landing-pages-in-claude" tabindex="-1">🎨 <strong><a href="https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Design converting landing pages in Claude</a></strong> <a class="header-anchor" href="#🎨-design-converting-landing-pages-in-claude" aria-label="Permalink to &quot;🎨 **[Design converting landing pages in Claude](https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn to use Anthropic’s new AI design tool — Claude Design — to generate four, high-converting mockup variations of your website’s landing page.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Go to claude.ai/design, select wireframe, click create, and describe who the page is for, the product, and the action visitors should take. Don’t hit “Send”</p></li><li><p>Screenshot a landing page you like (search top pages in your niche), as well as a page that does millions of daily transactions, like Amazon or eBay</p></li><li><p>Hit send with the brief and screenshots. Tell Claude to give four variations of the mockup. Answer any follow-up questions and wait 2-5 minutes</p></li><li><p>Refine with comments. Click any element and leave a note like &quot;rewrite this CTA to be outcome-specific&quot; or &quot;add a testimonial here.&quot; Claude applies the change</p></li></ol><p><strong>Pro tip:</strong> Click Share &gt; Handoff to Claude Code &gt; Send to Claude Code Web to get Claude Code to build and deploy the final website for you.</p><h6 id="presented-by-scrunch" tabindex="-1">PRESENTED BY SCRUNCH <a class="header-anchor" href="#presented-by-scrunch" aria-label="Permalink to &quot;PRESENTED BY SCRUNCH&quot;">​</a></h6><h4 id="🏆-ai-is-your-new-vip-visitor" tabindex="-1">🏆****<a href="http://scrunch.com/airundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"><strong>AI is your new VIP visitor</strong></a> <a class="header-anchor" href="#🏆-ai-is-your-new-vip-visitor" aria-label="Permalink to &quot;🏆****[**AI is your new VIP visitor**](http://scrunch.com/airundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)&quot;">​</a></h4><p><a href="https://scrunch.com/airundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Scrunch is the AI Customer Experience Platform that optimizes your site for AI bots — the new VIPs deciding whether your brand gets named, cited, or skipped when someone asks ChatGPT, Perplexity, or Claude about your category.</p><p><strong>With Scrunch, you&#39;ll:</strong></p><ul><li><p>See how AI reads your site today</p></li><li><p>Spot the blockers and content gaps</p></li><li><p>Deliver optimized pages straight to AI agents</p></li><li><p>Show up in more AI answers</p></li></ul><p><a href="http://scrunch.com/airundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Click here to see how AI reads your site</a>.</p><h6 id="ai-the-pentagon" tabindex="-1">AI &amp; THE PENTAGON <a class="header-anchor" href="#ai-the-pentagon" aria-label="Permalink to &quot;AI &amp; THE PENTAGON&quot;">​</a></h6><h4 id="🏛️-pentagon-announces-new-ai-partners" tabindex="-1">🏛️ <a href="https://www.washingtonpost.com/technology/2026/05/01/pentagon-ai-deals-microsoft-amazon-google-classified-military/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"><strong>Pentagon announces new AI partners</strong></a> <a class="header-anchor" href="#🏛️-pentagon-announces-new-ai-partners" aria-label="Permalink to &quot;🏛️ [**Pentagon announces new AI partners**](https://www.washingtonpost.com/technology/2026/05/01/pentagon-ai-deals-microsoft-amazon-google-classified-military/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> The Pentagon <a href="https://www.washingtonpost.com/technology/2026/05/01/pentagon-ai-deals-microsoft-amazon-google-classified-military/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">added</a> 8 AI companies to its classified networks while excluding Anthropic, even as the Washington Post reports the new contracts have the same autonomous-weapons and surveillance limits for which Anthropic was blacklisted.</p><p><strong>The details:</strong></p><ul><li><p>The official agreement list names SpaceX, OpenAI, Google, Nvidia, Reflection, Microsoft, AWS, and Oracle as the companies added to classified networks.</p></li><li><p>The Department of War said the new deals will “accelerate the transformation toward establishing the U.S. military as an AI-first fighting force”.</p></li><li><p>DoD CTO Emil Michael <a href="https://www.cnbc.com/2026/05/01/pentagon-anthropic-blacklist-mythos-michael.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">told</a> CNBC that Anthropic’s supply-chain risk label still stands, but called its Mythos model a &quot;separate national security moment.&quot;</p></li><li><p>Anthropic’s exclusion comes days after the White House came out against a broader Mythos rollout over compute concerns impacting its own access.</p></li></ul><p><strong>Why it matters:</strong> The White House seemingly wants to have its cake and eat it too — both continuing to shun Anthropic while also wanting priority access to its Mythos model despite the blacklist. There are also some interesting names on that list, namely Reflection, which raised $2B from 1789 Capital, a Donald Trump Jr.-backed fund.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-4" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-4" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)**&quot;">​</a></h3><ul><li><p>🗣️ <a href="https://www.rundown.ai/tools/custom-voices?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Custom Voices</a> - Clone voices with short clips for use in Grok applications</p></li><li><p>🦮 <a href="https://www.rundown.ai/tools/codex-pets?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Codex Pets</a> - OAI&#39;s animated companions for tracking active Codex work</p></li><li><p>🎶 <a href="https://www.rundown.ai/tools/eleven-music?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">ElevenMusic</a> - Platform for AI song generation, remixing, creator payouts</p></li><li><p>🚀 <a href="https://www.rundown.ai/tools/mimo-v2-5-pro?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">MiMo-V2.5-Pro</a> - Xiaomi&#39;s powerful new open-source model</p></li></ul><h3 id="📰-everything-else-in-ai-today-4" tabindex="-1">📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Everything else in AI today</a> <a class="header-anchor" href="#📰-everything-else-in-ai-today-4" aria-label="Permalink to &quot;📰 [Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)&quot;">​</a></h3><p><strong>OpenAI</strong><a href="https://developers.openai.com/codex/app/settings?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room#codex-pets" target="_blank" rel="noreferrer">shipped</a> Codex Pets, animated desktop companions that let you track agent progress without switching back to the app.</p><p><strong>OpenAI CEO Sam Altman</strong><a href="https://x.com/sama/status/2050357911915028689?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">announced</a> that OpenClaw users can use their ChatGPT subscriptions within the agentic tool, taking a stance against Anthropic’s <a href="https://www.rundown.ai/articles/anthropic-tells-openclaw-users-to-pay-up?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">restrictions</a>.</p><p><strong>Maryland</strong> <a href="https://www.nytimes.com/2026/05/01/business/surveillance-pricing-groceries-maryland.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">signed</a> the U.S.’s first ban on AI-driven grocery pricing, with fines up to $25K for stores caught using personalized shopper data to mark up prices.</p><p><strong>SAG-AFTRA</strong> <a href="https://deadline.com/2026/05/sag-aftra-studios-reach-new-bigger-deal-amptp-1236879157/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">secured</a> new AI guardrails in its four-year studio deal, with the guild&#39;s negotiator refusing to sign until Hollywood studios made concessions on AI protections.</p><p><strong>A Chinese court</strong> <a href="https://www.npr.org/2026/05/01/nx-s1-5807131/tech-worker-china-ai?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">ruled</a> that replacing a worker with AI does not legally justify firing them, ordering a tech firm to pay wrongful termination damages.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-4" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-4" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Olli T.</strong> in Finland:</p><p>&quot;I&#39;m a new real estate investor, and what I&#39;m struggling with is market insights, as in our county, there is no transparency or proper historical information available. With Gemini Pro, I created a concept that analyzes the market information.</p><p>The tool displays all relevant renovation history and future needs and can also generate an investment calculation. I then refined the concept with multiple free AIs (Claude, Codex), one prompt per day, to have a product that fits my needs.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-4" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-4" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.therundown.ai/p/the-white-house-rethinks-its-anthropic-fight?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">The White House rethinks its Anthropic fight</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/spacex-rocket-to-crash-into-the-moon?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">SpaceX is about to crash into the Moon</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/the-humanoid-baggage-handler-has-landed?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">A humanoid baggage handler has landed</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Create converting landing pages in Claude</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr>',372)])])}const d=t(o,[["render",i]]);export{c as __pageData,d as default};
